const db = $env.DETECTION_DB || 'ORCL';
const environment = $env.DETECTION_ENVIRONMENT || 'PROD';
const os = $env.DETECTION_OS || 'Windows';
const dbType = $env.DETECTION_DB_TYPE || 'Standalone';
const thresholdPct = Number($env.TABLESPACE_THRESHOLD_PCT || 90);
const criticalPct = Number($env.TABLESPACE_CRITICAL_PCT || 95);
const extendSizeGb = Number($env.TABLESPACE_EXTEND_SIZE_GB || 10);
const query = `WITH datafiles AS (
  SELECT tablespace_name, SUM(bytes) bytes
  FROM dba_data_files
  GROUP BY tablespace_name
),
free_space AS (
  SELECT tablespace_name, SUM(bytes) bytes
  FROM dba_free_space
  GROUP BY tablespace_name
)
SELECT
  d.tablespace_name,
  ROUND(d.bytes / 1024 / 1024 / 1024, 2) AS total_gb,
  ROUND((d.bytes - NVL(f.bytes, 0)) / 1024 / 1024 / 1024, 2) AS used_gb,
  ROUND(NVL(f.bytes, 0) / 1024 / 1024 / 1024, 2) AS free_gb,
  ROUND(((d.bytes - NVL(f.bytes, 0)) / d.bytes) * 100, 2) AS usage_pct
FROM datafiles d
LEFT JOIN free_space f ON f.tablespace_name = d.tablespace_name
ORDER BY usage_pct DESC`;
return [{ json: { db, environment, os, db_type: dbType, threshold_pct: thresholdPct, critical_pct: criticalPct, extend_size_gb: extendSizeGb, query } }];

const context = $('Prepare Detection Context').first().json;
const rows = $input.all().map((item) => item.json);
const executionId = $execution.id || Date.now();
function pick(row, ...keys) {
  for (const key of keys) {
    if (row[key] != null && row[key] !== '') return row[key];
    const upper = key.toUpperCase();
    const lower = key.toLowerCase();
    if (row[upper] != null && row[upper] !== '') return row[upper];
    if (row[lower] != null && row[lower] !== '') return row[lower];
  }
  return undefined;
}
const alerts = [];
for (const row of rows) {
  const tablespace = String(pick(row, 'tablespace_name') || '').trim().toUpperCase();
  const usagePct = Number(pick(row, 'usage_pct') || 0);
  if (!tablespace || usagePct < Number(context.threshold_pct)) continue;
  const usedGb = Number(pick(row, 'used_gb') || 0);
  const freeGb = Number(pick(row, 'free_gb') || 0);
  const totalGb = Number(pick(row, 'total_gb') || 0);
  const severity = usagePct >= Number(context.critical_pct) ? 'critical' : 'warning';
  const idempotencyKey = `tablespace:${context.db}:${context.environment}:${tablespace}`;
  alerts.push({
    event_id: `evt_${executionId}_${tablespace}`,
    correlation_id: `corr_${executionId}_${tablespace}`,
    idempotency_key: idempotencyKey,
    action: 'tablespace',
    alert_type: 'tablespace',
    source: 'n8n',
    db: context.db,
    severity,
    requested_by: 'n8n',
    environment: context.environment,
    os: context.os,
    db_type: context.db_type,
    message: `Tablespace ${tablespace} on ${context.db} is ${usagePct}% used. Recommended extension: ${context.extend_size_gb} GB.`,
    params: {
      tablespace,
      usage_pct: usagePct,
      threshold_pct: Number(context.threshold_pct),
      critical_pct: Number(context.critical_pct),
      used_gb: usedGb,
      free_gb: freeGb,
      total_gb: totalGb,
      extend_size_gb: Number(context.extend_size_gb),
      recommendation: `Extend ${tablespace} by ${context.extend_size_gb} GB`
    },
    metadata: {
      workflow: 'DBA - Tablespace Detection',
      execution_id: executionId,
      total_gb: totalGb
    }
  });
}
return alerts.map((alert) => ({ json: alert }));
